def gen(rng, size):
    n = max(1, size)
    nums = list(range(n))
    swaps = rng.randint(0, n)
    for _ in range(swaps):
        if rng.random() < 0.7 and n >= 2:
            i = rng.randint(0, n - 2)
            nums[i], nums[i + 1] = nums[i + 1], nums[i]
        elif n >= 2:
            i = rng.randint(0, n - 1)
            j = rng.randint(0, n - 1)
            nums[i], nums[j] = nums[j], nums[i]
    return [nums]

