class Solution:
    def isIdealPermutation(self, nums):
        n = len(nums)
        glob = 0
        for i in range(n):
            for j in range(i + 1, n):
                if nums[i] > nums[j]:
                    glob += 1
        loc = sum(1 for i in range(n - 1) if nums[i] > nums[i + 1])
        return glob == loc

